local OlIOIlOI000=33
local Ol0l0lOO0O0=245
local OIIlOI0lOlO="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function O0lO0III0IO(d)
    d=(d or ""):gsub("%s+","")
    d=d:gsub("[^"..OIIlOI0lOlO.."=]","")
    return (d:gsub(".",function(x)
        if x=="=" then return "" end
        local r,f="",(OIIlOI0lOlO:find(x,1,true)-1)
        for i=6,1,-1 do
            r=r..(f%2^i-f%2^(i-1)>0 and "1" or "0")
        end
        return r
    end):gsub("%d%d%d?%d?%d?%d?%d?%d?",function(x)
        if #x~=8 then return "" end
        local c=0
        for i=1,8 do
            if x:sub(i,i)=="1" then c=c+2^(8-i) end
        end
        return string.char(c)
    end))
end
local function O0IOlII0000(a,b)
    local r,m=0,1
    while a>0 or b>0 do
        local aa=a%2
        local bb=b%2
        if aa~=bb then r=r+m end
        a=(a-aa)/2
        b=(b-bb)/2
        m=m*2
    end
    return r
end
local OIlllOOOOOl=OlO0llOIIIl:gsub("[^A-Za-z0-9+/=]","")
OIlllOOOOOl=string.reverse(OIlllOOOOOl)
local OIO0lIO0I00=O0lO0III0IO(OIlllOOOOOl)
local OIOIOllOlII={}
for OIlIOl0llIl=1,#OIO0lIO0I00 do
    local OO0IlIOIllI=OIO0lIO0I00:byte(OIlIOl0llIl)
    local OO00IlIO00O=(OO0IlIOIllI-((Ol0l0lOO0O0+OIlIOl0llIl)%256))%256
    OIOIOllOlII[OIlIOl0llIl]=string.char(O0IOlII0000(OO00IlIO00O,OlIOIlOI000))
end
local OO00OI0IOOO=table.concat(OIOIOllOlII)
local OlI0IlOOlOl=loadstring or load
local OO0OlI0lllO,O0II0OOIllI=OlI0IlOOlOl(OO00OI0IOOO)
if not OO0OlI0lllO then error(O0II0OOIllI) end
return OO0OlI0lllO()
